    @Test
    fun `SøknadEndretTilstandMelding ikke legger til søknadsdata når status går over til påbegynt`() {
        val søknadEndretTilstandMelding =
            SøknadEndretTilstandMelding(
                søknadId = UUID.randomUUID(),
                ident = "12345678910",
                forrigeTilstand = "UnderOpprettelse",
                nyTilstand = "PÅBEGYNT",
            ).asMessage()

        søknadEndretTilstandMelding.toJson().shouldNotContainJsonKey("søknadsdata")
    }

    private val seksjoner: List<SeksjonMedTidstempler> =
        listOf(
            SeksjonMedTidstempler(
                seksjonId = "personalia",
                data =
                    """{"id": "personalia","seksjonsvar": {"fornavnFraPdl": "SOSIAL","mellomnavnFraPdl": "","etternavnFraPdl": "MOLDVARP","fødselsnummerFraPdl": "10928095547","alderFraPdl": "44","adresselinje1FraPdl": "Nygårdsveien 17B","adresselinje2FraPdl": "","adresselinje3FraPdl": "","postnummerFraPdl": "3214","poststedFraPdl": "Sandefjord","landkodeFraPdl": "NO","landFraPdl": "NORGE","kontonummerFraKontoregister": "","folkeregistrertAdresseErNorgeStemmerDet": "nei","bostedsland": "NOR"},"versjon": 1}"""
                        .trim(),
                opprettet = LocalDateTime.now(),
                oppdatert = LocalDateTime.now(),
            ),
            SeksjonMedTidstempler(
                seksjonId = "verneplikt",
                data =
                    """{"seksjonId": "verneplikt","seksjon": {"avtjentVerneplikt": "ja"},"versjon": 1}""".trim(),
                opprettet = LocalDateTime.now(),
                oppdatert = LocalDateTime.now(),
            ),
        )
}
